class BoundedQueue(T)
  @capacity : Int32
  @queue : Array(T)

  def initialize(@capacity : Int32)
    @queue = Array(T).new
  end

  def enqueue(item : T) : Nil
    if @queue.size < @capacity
      @queue << item
    end
  end

  def dequeue : T?
    @queue.shift?
  end

  def size : Int32
    @queue.size
  end
end
